const PROCESSING_FEE = 5;
const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export function runScenario(
  steps: { items: { type: string }[] }[],
): unknown[] {
  return steps.map((step) => ({
    premium:
      PROCESSING_FEE +
      step.items.reduce(
        (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
        0,
      ),
  }));
}
